{
  "family": "Pinner Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "CCO"
    ],
    "product_smiles": [
      "CC(=[NH2+])OCC.[Cl-]"
    ],
    "optional_reagent_smiles": [
      "Cl"
    ],
    "rationale": "This reaction shows the formation of an imino ether hydrochloride salt (a Pinner salt) from the simplest common nitrile (acetonitrile) and alcohol (ethanol) in the presence of dry hydrogen chloride. This represents the core transformation of the Pinner reaction, which is the acid-catalyzed addition of an alcohol to a nitrile. The resulting Pinner salt is a key intermediate for subsequent hydrolysis to esters or aminolysis to amidines.",
    "collision_avoidance_note": "The reaction uses simple, acyclic, saturated aliphatic substrates (acetonitrile, ethanol) to avoid overlap with reactions involving aromatic rings, unsaturation, or complex functional groups. The product is the characteristic imino ether salt, which is specific to the Pinner reaction and distinct from products of other nitrile transformations like the Stephen reduction (aldehydes) or Blaise reaction (beta-ketoesters)."
  }
}
